import json
import re

# Load UC publication numbers from previous result
uc_pub_numbers = set(locals()['var_functions.execute_python:54']['uc_publication_numbers'])
print('UC publication numbers loaded:', len(uc_pub_numbers))

# Process the sample citation data to find matches
with open(locals()['var_functions.query_db:46'], 'r') as f:
    sample_data = json.load(f)

print('Sample data records:', len(sample_data))

# Check for citations to UC patents
matches = []
for record in sample_data:
    patents_info = record.get('Patents_info', '')
    citations = record.get('citation', '[]')

    if 'UNIV CALIFORNIA' not in patents_info and citations != '[]':
        try:
            citation_list = json.loads(citations)
            for cite in citation_list:
                if cite.get('publication_number') in uc_pub_numbers:
                    # Extract assignee
                    assignee = ''
                    if 'holds' in patents_info:
                        assignee = patents_info.split(' holds')[0]
                    elif 'assigned to' in patents_info:
                        assignee = patents_info.split(' assigned to')[1].split(' and')[0].strip()
                    elif 'is owned by' in patents_info:
                        assignee = patents_info.split(' is owned by')[1].split(' and')[0].strip()
                    elif 'is belonging to' in patents_info:
                        assignee = patents_info.split(' is belonging to')[1].split(' and')[0].strip()
                    else:
                        # Try first few words
                        words = patents_info.split()[:3]
                        assignee = ' '.join(words)

                    matches.append({
                        'assignee': assignee.strip(),
                        'cited_publication': cite.get('publication_number'),
                        'citing_patent_info': patents_info
                    })
                    break
        except:
            continue

print('Found matches:', len(matches))
if matches:
    print('\nSample match:')
    print(json.dumps(matches[0], indent=2))

result = {
    'matches_count': len(matches),
    'matches': matches
}
print('\n__RESULT__:')
print(json.dumps(result))

